import React, { useEffect } from "react";

const SplashScreen = ({ onComplete }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onComplete();
    }, 2000); // match animation duration

    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-[#0f172a] flex flex-col justify-center items-center z-50">
      <div className="text-center animate-riseFadeOut">
        <h1 className="text-4xl md:text-6xl font-extrabold text-cyan-300 tracking-widest">
          NEURAL NINJA'S
        </h1>
        <h1 className="text-xl md:text-2xl font-medium text-cyan-200 mt-2">
          BOT
        </h1>
      </div>
    </div>
  );
};

export default SplashScreen;
